#!/bin/bash\n\n################################################################################\n# GESTOR DE CRГ‰DITOS - Script Maestro Automatizado para Termux\n# VersiГіn: 2.0.0\n# Plataforma: Termux en Android\n# DescripciГіn: Instala todo y compila automГЎticamente ambas versiones\n################################################################################\n\n# Colores para salida\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nBLUE='\\033[0;34m'\nMAGENTA='\\033[0;35m'\nCYAN='\\033[0;36m'\nNC='\\033[0m' # No Color\n\n# Variables\nPROJECT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nDIST_DIR=\"$PROJECT_DIR/dist\"\nAPK_DIR=\"$DIST_DIR/apks\"\nLOG_FILE=\"$DIST_DIR/setup-build-termux.log\"\nTIMESTAMP=$(date +\"%Y-%m-%d_%H-%M-%S\")\nBUILD_REPORT=\"$DIST_DIR/build-report-$TIMESTAMP.txt\"\nSTART_TIME=$(date +%s)\n\n# FunciГіn para mostrar banner\nshow_banner() {\n    clear\n    echo -e \"${CYAN}\"\n    echo \"в•”в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•—\"\n    echo \"в•‘                                                               в•‘\"\n    echo \"в•‘     GESTOR DE CRГ‰DITOS Y COBRANZAS - COMPILACIГ“N TERMUX      в•‘\"\n    echo \"в•‘                                                               в•‘\"\n    echo \"в•‘              Script Maestro Automatizado v2.0.0               в•‘\"\n    echo \"в•‘                                                               в•‘\"\n    echo \"в•љв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ќ\"\n    echo -e \"${NC}\"\n}\n\n# Funciones de utilidad\nprint_section() {\n    echo \"\"\n    echo -e \"${MAGENTA}в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ${NC}\"\n    echo -e \"${MAGENTA}$1${NC}\"\n    echo -e \"${MAGENTA}в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ${NC}\"\n}\n\nprint_success() {\n    echo -e \"${GREEN}вњ… $1${NC}\"\n}\n\nprint_error() {\n    echo -e \"${RED}вќЊ $1${NC}\"\n}\n\nprint_warning() {\n    echo -e \"${YELLOW}вљ пёЏ  $1${NC}\"\n}\n\nprint_info() {\n    echo -e \"${BLUE}в„№пёЏ  $1${NC}\"\n}\n\nprint_progress() {\n    echo -e \"${CYAN}вЏі $1${NC}\"\n}\n\nlog_message() {\n    echo \"[$TIMESTAMP] $1\" >> \"$LOG_FILE\"\n}\n\n# FunciГіn para calcular tiempo transcurrido\nget_elapsed_time() {\n    local end_time=$(date +%s)\n    local elapsed=$((end_time - START_TIME))\n    local hours=$((elapsed / 3600))\n    local minutes=$(((elapsed % 3600) / 60))\n    local seconds=$((elapsed % 60))\n    printf \"%02d:%02d:%02d\" $hours $minutes $seconds\n}\n\n# FunciГіn para actualizar Termux\nupdate_termux() {\n    print_section \"рџ”„ Actualizando Termux\"\n    \n    print_progress \"Actualizando repositorios...\"\n    if pkg update -y 2>&1 | tail -5 >> \"$LOG_FILE\"; then\n        print_success \"Repositorios actualizados\"\n    else\n        print_error \"Error al actualizar repositorios\"\n        return 1\n    fi\n    \n    print_progress \"Actualizando paquetes...\"\n    if pkg upgrade -y 2>&1 | tail -5 >> \"$LOG_FILE\"; then\n        print_success \"Paquetes actualizados\"\n    else\n        print_error \"Error al actualizar paquetes\"\n        return 1\n    fi\n    \n    return 0\n}\n\n# FunciГіn para instalar dependencias del sistema\ninstall_system_dependencies() {\n    print_section \"рџ“¦ Instalando Dependencias del Sistema\"\n    \n    local packages=(\"nodejs\" \"npm\" \"git\" \"curl\" \"wget\" \"build-essential\")\n    \n    for package in \"${packages[@]}\"; do\n        print_progress \"Verificando $package...\"\n        \n        if pkg list-installed 2>/dev/null | grep -q \"^$package/\"; then\n            print_success \"$package ya estГЎ instalado\"\n        else\n            print_progress \"Instalando $package...\"\n            if pkg install -y \"$package\" 2>&1 | tail -3 >> \"$LOG_FILE\"; then\n                print_success \"$package instalado\"\n            else\n                print_warning \"Error al instalar $package (continuando...)\"\n            fi\n        fi\n    done\n    \n    return 0\n}\n\n# FunciГіn para verificar requisitos\nverify_requirements() {\n    print_section \"рџ”Ќ Verificando Requisitos\"\n    \n    local all_ok=true\n    \n    # Verificar Node.js\n    if command -v node &> /dev/null; then\n        local node_version=$(node --version)\n        print_success \"Node.js $node_version encontrado\"\n    else\n        print_error \"Node.js no encontrado\"\n        all_ok=false\n    fi\n    \n    # Verificar npm\n    if command -v npm &> /dev/null; then\n        local npm_version=$(npm --version)\n        print_success \"npm $npm_version encontrado\"\n    else\n        print_error \"npm no encontrado\"\n        all_ok=false\n    fi\n    \n    # Verificar git\n    if command -v git &> /dev/null; then\n        local git_version=$(git --version)\n        print_success \"$git_version encontrado\"\n    else\n        print_warning \"git no encontrado (opcional)\"\n    fi\n    \n    # Verificar espacio en disco\n    local available_space=$(df $PROJECT_DIR | awk 'NR==2 {print $4}')\n    if [ \"$available_space\" -gt 5242880 ]; then  # 5GB en KB\n        print_success \"Espacio disponible: $(numfmt --to=iec-i --suffix=B $((available_space * 1024)) 2>/dev/null || echo \"$available_space KB\")\"\n    else\n        print_error \"Espacio insuficiente (necesita mГ­nimo 5GB)\"\n        all_ok=false\n    fi\n    \n    if [ \"$all_ok\" = true ]; then\n        print_success \"Todos los requisitos estГЎn satisfechos\"\n        return 0\n    else\n        return 1\n    fi\n}\n\n# FunciГіn para instalar dependencias del proyecto\ninstall_project_dependencies() {\n    print_section \"рџ“љ Instalando Dependencias del Proyecto\"\n    \n    cd \"$PROJECT_DIR\" || return 1\n    \n    print_progress \"Limpiando cachГ© de npm...\"\n    npm cache clean --force 2>&1 | tail -2 >> \"$LOG_FILE\"\n    \n    print_progress \"Instalando dependencias con npm...\"\n    if npm install 2>&1 | tee -a \"$LOG_FILE\" | tail -10; then\n        print_success \"Dependencias del proyecto instaladas\"\n        return 0\n    else\n        print_error \"Error al instalar dependencias del proyecto\"\n        return 1\n    fi\n}\n\n# FunciГіn para instalar EAS CLI\ninstall_eas_cli() {\n    print_section \"рџљЂ Configurando EAS CLI\"\n    \n    if command -v eas &> /dev/null; then\n        local eas_version=$(eas --version)\n        print_success \"EAS CLI $eas_version ya estГЎ instalado\"\n        return 0\n    fi\n    \n    print_progress \"Instalando EAS CLI globalmente...\"\n    if npm install -g eas-cli 2>&1 | tail -5 >> \"$LOG_FILE\"; then\n        print_success \"EAS CLI instalado\"\n        return 0\n    else\n        print_error \"Error al instalar EAS CLI\"\n        return 1\n    fi\n}\n\n# FunciГіn para compilar versiГіn Admin\ncompile_admin() {\n    print_section \"рџ”§ Compilando VersiГіn ADMIN\"\n    \n    cd \"$PROJECT_DIR\" || return 1\n    \n    # Asegurar que app.json es la versiГіn Admin\n    if [ ! -f \"app.json\" ]; then\n        print_error \"app.json no encontrado\"\n        return 1\n    fi\n    \n    print_info \"Usando configuraciГіn Admin (app.json)\"\n    print_progress \"Iniciando compilaciГіn con EAS...\"\n    print_warning \"Esto puede tomar 15-30 minutos. Por favor, espera...\"\n    \n    if eas build --platform android --local 2>&1 | tee -a \"$LOG_FILE\" | tail -20; then\n        print_success \"APK Admin compilado exitosamente\"\n        \n        # Buscar el APK generado\n        local apk_file=$(find . -name \"*.apk\" -type f -mmin -60 2>/dev/null | head -1)\n        if [ -n \"$apk_file\" ]; then\n            mkdir -p \"$APK_DIR\"\n            cp \"$apk_file\" \"$APK_DIR/gestor-creditos-admin-$TIMESTAMP.apk\"\n            print_success \"APK copiado a: $APK_DIR/gestor-creditos-admin-$TIMESTAMP.apk\"\n            log_message \"APK Admin compilado: $apk_file\"\n        fi\n        return 0\n    else\n        print_error \"Error al compilar versiГіn Admin\"\n        return 1\n    fi\n}\n\n# FunciГіn para compilar versiГіn Invitado\ncompile_guest() {\n    print_section \"рџ‘Ґ Compilando VersiГіn INVITADO\"\n    \n    cd \"$PROJECT_DIR\" || return 1\n    \n    # Cambiar a configuraciГіn Guest\n    if [ ! -f \"app-guest.json\" ]; then\n        print_error \"app-guest.json no encontrado\"\n        return 1\n    fi\n    \n    print_info \"Cambiando a configuraciГіn Invitado (app-guest.json)\"\n    cp app.json app.json.backup\n    cp app-guest.json app.json\n    \n    print_progress \"Iniciando compilaciГіn con EAS...\"\n    print_warning \"Esto puede tomar 15-30 minutos. Por favor, espera...\"\n    \n    if eas build --platform android --local 2>&1 | tee -a \"$LOG_FILE\" | tail -20; then\n        print_success \"APK Invitado compilado exitosamente\"\n        \n        # Buscar el APK generado\n        local apk_file=$(find . -name \"*.apk\" -type f -mmin -60 2>/dev/null | head -1)\n        if [ -n \"$apk_file\" ]; then\n            mkdir -p \"$APK_DIR\"\n            cp \"$apk_file\" \"$APK_DIR/gestor-creditos-guest-$TIMESTAMP.apk\"\n            print_success \"APK copiado a: $APK_DIR/gestor-creditos-guest-$TIMESTAMP.apk\"\n            log_message \"APK Invitado compilado: $apk_file\"\n        fi\n        \n        # Restaurar configuraciГіn original\n        if [ -f \"app.json.backup\" ]; then\n            mv app.json.backup app.json\n            print_info \"ConfiguraciГіn original restaurada\"\n        fi\n        return 0\n    else\n        print_error \"Error al compilar versiГіn Invitado\"\n        # Restaurar configuraciГіn original\n        if [ -f \"app.json.backup\" ]; then\n            mv app.json.backup app.json\n        fi\n        return 1\n    fi\n}\n\n# FunciГіn para limpiar archivos temporales\nclean_temp() {\n    print_section \"рџ§№ Limpiando Archivos Temporales\"\n    \n    cd \"$PROJECT_DIR\" || return 1\n    \n    rm -f app.json.backup\n    rm -rf .expo\n    npm cache clean --force 2>&1 | tail -2 >> \"$LOG_FILE\"\n    \n    print_success \"Archivos temporales limpiados\"\n}\n\n# FunciГіn para generar reporte final\ngenerate_final_report() {\n    print_section \"рџ“Љ Generando Reporte Final\"\n    \n    local elapsed_time=$(get_elapsed_time)\n    \n    cat > \"$BUILD_REPORT\" << EOF\nв•”в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•—\nв•‘                                                               в•‘\nв•‘    GESTOR DE CRГ‰DITOS - REPORTE DE COMPILACIГ“N (Termux)      в•‘\nв•‘                                                               в•‘\nв•љв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ќ\n\nрџ“… Fecha: $TIMESTAMP\nвЏ±пёЏ  Tiempo Total: $elapsed_time\nрџ“± Plataforma: Termux (Android)\nрџ“‚ Directorio: $PROJECT_DIR\n\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\nвњ… VERSIONES COMPILADAS\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\n\nрџ“± VersiГіn Admin\n   в”њв”Ђ Acceso: Completo\n   в”њв”Ђ GestiГіn de deudores: вњ…\n   в”њв”Ђ CreaciГіn de pagos: вњ…\n   в”њв”Ђ Reportes y grГЎficos: вњ…\n   в”њв”Ђ GestiГіn de usuarios: вњ…\n   в””в”Ђ Notificaciones: вњ…\n\nрџ“± VersiГіn Invitado\n   в”њв”Ђ Acceso: Solo lectura\n   в”њв”Ђ VisualizaciГіn de deudores: вњ…\n   в”њв”Ђ Consulta de pagos: вњ…\n   в”њв”Ђ VisualizaciГіn de reportes: вњ…\n   в””в”Ђ Acceso limitado: вњ…\n\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\nрџ“Ѓ ARCHIVOS GENERADOS\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\n\nAPKs compilados:\nEOF\n    \n    ls -lh $APK_DIR/*.apk 2>/dev/null | awk '{print \"  \" $9 \" (\" $5 \")\"}' >> \"$BUILD_REPORT\" || echo \"  No hay APKs generados\" >> \"$BUILD_REPORT\"\n    \n    cat >> \"$BUILD_REPORT\" << EOF\n\nArchivos de log:\n  $LOG_FILE\n  $BUILD_REPORT\n\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\nрџљЂ PRГ“XIMOS PASOS\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\n\n1. вњ… Los APKs estГЎn listos en: $APK_DIR\n\n2. рџ“± Transferir APKs a tu dispositivo:\n   - Abre el administrador de archivos\n   - Navega a: /data/data/com.termux/files/home/gestor-creditos-app/dist/apks/\n   - Copia los archivos .apk a tu carpeta de Descargas\n\n3. рџ“Ґ Instalar en tu dispositivo:\n   - Abre el administrador de archivos\n   - Ve a Descargas\n   - Toca cada APK para instalar\n   - Permite la instalaciГіn desde fuentes desconocidas si es necesario\n\n4. рџљЂ Abrir la aplicaciГіn:\n   - Ve a tu pantalla de inicio\n   - Busca \"Gestor de CrГ©ditos\"\n   - Toca para abrir\n\n5. рџ‘¤ Crear cuenta:\n   - Completa el formulario de registro\n   - Crea tu contraseГ±a\n   - ВЎComienza a usar!\n\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\nрџ“ћ INFORMACIГ“N DE SOPORTE\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\n\nEmail: support@gestorcreditos.com\nDocumentaciГіn: Consulta los archivos .md\nLogs completos: $LOG_FILE\n\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\nвњЁ ВЎCOMPILACIГ“N COMPLETADA EXITOSAMENTE!\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\n\nEOF\n    \n    print_success \"Reporte generado: $BUILD_REPORT\"\n}\n\n# FunciГіn para mostrar resumen\nshow_summary() {\n    local elapsed_time=$(get_elapsed_time)\n    \n    echo \"\"\n    echo -e \"${CYAN}в•”в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•—${NC}\"\n    echo -e \"${CYAN}в•‘                                                               в•‘${NC}\"\n    echo -e \"${GREEN}в•‘           вњ… COMPILACIГ“N COMPLETADA EXITOSAMENTE вњ…            в•‘${NC}\"\n    echo -e \"${CYAN}в•‘                                                               в•‘${NC}\"\n    echo -e \"${CYAN}в•љв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ќ${NC}\"\n    echo \"\"\n    echo -e \"${GREEN}Tiempo total: $elapsed_time${NC}\"\n    echo -e \"${GREEN}APKs generados: 2 (Admin + Invitado)${NC}\"\n    echo -e \"${GREEN}UbicaciГіn: $APK_DIR${NC}\"\n    echo \"\"\n    echo -e \"${YELLOW}рџ“Ѓ Archivos generados:${NC}\"\n    ls -lh $APK_DIR/*.apk 2>/dev/null | awk '{print \"   \" $9 \" (\" $5 \")\"}' || echo \"   No hay APKs\"\n    echo \"\"\n    echo -e \"${BLUE}рџ“Љ Reporte: $BUILD_REPORT${NC}\"\n    echo -e \"${BLUE}рџ“‹ Logs: $LOG_FILE${NC}\"\n    echo \"\"\n}\n\n# FunciГіn principal\nmain() {\n    show_banner\n    \n    # Crear directorio de logs\n    mkdir -p \"$DIST_DIR\" \"$APK_DIR\"\n    \n    # Inicializar log\n    echo \"=== CompilaciГіn Maestro Iniciada: $TIMESTAMP ===\" > \"$LOG_FILE\"\n    log_message \"Directorio del proyecto: $PROJECT_DIR\"\n    \n    # Mostrar informaciГіn inicial\n    print_info \"Directorio: $PROJECT_DIR\"\n    print_info \"Logs: $LOG_FILE\"\n    print_info \"APKs: $APK_DIR\"\n    echo \"\"\n    \n    # Paso 1: Actualizar Termux\n    if ! update_termux; then\n        print_error \"Error al actualizar Termux\"\n        return 1\n    fi\n    \n    # Paso 2: Instalar dependencias del sistema\n    if ! install_system_dependencies; then\n        print_error \"Error al instalar dependencias del sistema\"\n        return 1\n    fi\n    \n    # Paso 3: Verificar requisitos\n    if ! verify_requirements; then\n        print_error \"No se pueden satisfacer los requisitos\"\n        return 1\n    fi\n    \n    # Paso 4: Instalar dependencias del proyecto\n    if ! install_project_dependencies; then\n        print_error \"Error al instalar dependencias del proyecto\"\n        return 1\n    fi\n    \n    # Paso 5: Instalar EAS CLI\n    if ! install_eas_cli; then\n        print_error \"Error al instalar EAS CLI\"\n        return 1\n    fi\n    \n    # Paso 6: Compilar Admin\n    if ! compile_admin; then\n        print_error \"Error al compilar versiГіn Admin\"\n        return 1\n    fi\n    \n    # Paso 7: Compilar Invitado\n    if ! compile_guest; then\n        print_error \"Error al compilar versiГіn Invitado\"\n        return 1\n    fi\n    \n    # Paso 8: Limpiar archivos temporales\n    clean_temp\n    \n    # Paso 9: Generar reporte final\n    generate_final_report\n    \n    # Mostrar resumen\n    show_summary\n    \n    print_success \"ВЎTodo completado! Los APKs estГЎn listos para instalar.\"\n    return 0\n}\n\n# Ejecutar funciГіn principal\nmain\nexit $?\n
